import type { MapRef } from '@vis.gl/react-maplibre';

import { _sanitizeSymbol } from '@dynatrace/strato-components/core';

import { attachImageFromShape } from './attach-image-from-shape.js';
import { attachImageFromText } from './attach-image-from-text.js';
import { isValidShape } from './is-valid-shape.js';
import type { MapShape } from '../types/shapes.js';

export const attachImageFromString = (
  map: MapRef,
  shape: MapShape | string,
  suffix = '',
  outputSize?: number,
) => {
  const isShape = isValidShape(shape);
  const name = isShape ? `${shape}-${suffix}` : `emoji-${suffix}`;

  if (isShape) {
    attachImageFromShape(map, shape, name, outputSize);
  } else {
    const sanitizedShape = _sanitizeSymbol(shape);
    attachImageFromText(map, sanitizedShape, name, outputSize);
  }
};
